"use client";

import { useEffect, useRef, useState } from "react";
import styles from "@/app/live/page.module.css";

interface Video {
  id: number;
  title: string;
  description: string | null;
  type: string;
  url: string;
  thumbnail: string | null;
  views: number;
  likes: number;
  isFeatured: boolean;
  createdAt: any;
}

interface LivePlayerProps {
  initialLiveStream: Video | null;
}

interface ChatMessage {
  id: number;
  user: string;
  text: string;
  isSelf?: boolean;
  time: string;
}

export default function LivePlayer({ initialLiveStream }: LivePlayerProps) {
  const [liveStream] = useState<Video | null>(initialLiveStream);
  const [viewerCount, setViewerCount] = useState(1420);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([
    { id: 1, user: "أحمد الورفلي", text: "ما شاء الله البث ممتاز والصورة واضحة جداً 👍", time: "20:00" },
    { id: 2, user: "فاطمة طرابلسية", text: "تحية طيبة لكم من طرابلس الغرب، تغطية رائعة!", time: "20:01" },
    { id: 3, user: "عبدالرحمن بنغازي", text: "هل في موعد محدد لنشرة الأخبار القادمة؟", time: "20:02" },
    { id: 4, user: "سند المصراتي", text: "بالتوفيق والنجاح دائماً لقناة ليبيا بلس 🇱🇾", time: "20:03" },
  ]);
  const [chatInput, setChatInput] = useState("");

  const chatEndRef = useRef<HTMLDivElement>(null);

  // Pool of mock chat messages to dynamically inject
  const mockChatPool = [
    { user: "منير السبهاوي", text: "متابعكم من سبها الحبيبة، كل التوفيق لكم ❤️" },
    { user: "سالي الخمس", text: "قناة متميزة وبرامج هادفة جداً" },
    { user: "علي الزاوية", text: "أجمل بث مباشر وقناة سريعة التحميل" },
    { user: "محمد الدرناوي", text: "تحياتنا لجميع الطاقم الإعلامي المميز" },
    { user: "إيناس الخمس", text: "الصوت والصورة بجودة HD، عمل احترافي" },
    { user: "خالد البيضاء", text: "تغطية متميزة جداً لآخر التطورات" },
    { user: "جمال الجفرة", text: "ما شاء الله، ربي يوفقكم ويبارك في جهودكم" },
  ];

  // 1. Scroll chat box to bottom
  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatMessages]);

  // 2. Simulate fluctuating viewer count
  useEffect(() => {
    const viewerInterval = setInterval(() => {
      setViewerCount((prev) => {
        const delta = Math.floor(Math.random() * 9) - 4; // Fluctuate by -4 to +4
        return Math.max(1200, prev + delta);
      });
    }, 4000);

    return () => clearInterval(viewerInterval);
  }, []);

  // 3. Simulate periodic incoming chat messages
  useEffect(() => {
    const chatInterval = setInterval(() => {
      const randomIndex = Math.floor(Math.random() * mockChatPool.length);
      const chosenMock = mockChatPool[randomIndex];
      const now = new Date();
      const timeString = `${now.getHours().toString().padStart(2, "0")}:${now.getMinutes().toString().padStart(2, "0")}`;

      const newMsg: ChatMessage = {
        id: Date.now(),
        user: chosenMock.user,
        text: chosenMock.text,
        time: timeString,
      };

      setChatMessages((prev) => [...prev, newMsg]);
    }, 6000);

    return () => clearInterval(chatInterval);
  }, []);

  // 4. Handle custom chat sending
  const handleSendChat = (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim()) return;

    const now = new Date();
    const timeString = `${now.getHours().toString().padStart(2, "0")}:${now.getMinutes().toString().padStart(2, "0")}`;

    const newMsg: ChatMessage = {
      id: Date.now(),
      user: "أنت (مشاهد)",
      text: chatInput.trim(),
      isSelf: true,
      time: timeString,
    };

    setChatMessages((prev) => [...prev, newMsg]);
    setChatInput("");
  };

  if (!liveStream) {
    return (
      <div className={styles.container}>
        <div style={{ textAlign: "center", padding: "80px 20px" }} className="glass-card">
          <span style={{ fontSize: "3rem" }}>📡</span>
          <h2 style={{ marginTop: "20px" }}>لا يوجد بث مباشر مفعل حالياً</h2>
          <p style={{ color: "var(--text-secondary)", marginTop: "10px" }}>
            يرجى تفعيل البث المباشر ووسم البث كـ "مميز" في لوحة التحكم لبدء البث!
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      {/* Page Title Area */}
      <div className={styles.titleArea}>
        <h1 className={styles.liveTitle}>
          <span className="liveDot"></span>
          {liveStream.title}
        </h1>
        <div className={styles.liveCount}>
          <span>🔴</span>
          <span>{viewerCount.toLocaleString()} يشاهدون الآن</span>
        </div>
      </div>

      {/* Broadcast Split Grid */}
      <div className={styles.broadcastGrid}>

        {/* Cinema Video Player Container */}
        <div className={styles.playerWrapper}>
          <iframe
            src={`${liveStream.url}?autoplay=1&mute=0&rel=0`}
            title={liveStream.title}
            className={styles.iframeElement}
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
            allowFullScreen
          />
        </div>

        {/* Live Interactive Chat Area */}
        <div className={styles.chatContainer}>
          <div className={styles.chatHeader}>
            <span>💬</span>
            <span>الدردشة الحية التفاعلية</span>
          </div>

          {/* Messages Flow */}
          <div className={styles.chatMessages}>
            {chatMessages.map((msg) => (
              <div
                key={msg.id}
                className={`${styles.chatBubble} ${msg.isSelf ? styles.currentUserBubble : ""}`}
              >
                <span className={`${styles.chatUser} ${msg.isSelf ? styles.systemUser : ""}`}>
                  👤 {msg.user}
                  <span style={{ fontSize: "0.65rem", color: "var(--text-muted)", fontWeight: "normal" }}>
                    {msg.time}
                  </span>
                </span>
                <span className={styles.chatText}>{msg.text}</span>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>

          {/* Submission Footer */}
          <div className={styles.chatFooter}>
            <form onSubmit={handleSendChat} className={styles.chatForm}>
              <input
                type="text"
                placeholder="اكتب رسالتك هنا..."
                className={styles.chatInput}
                value={chatInput}
                onChange={(e) => setChatInput(e.target.value)}
                maxLength={100}
              />
              <button type="submit" className={styles.sendBtn} title="إرسال">
                ✈️
              </button>
            </form>
          </div>
        </div>

      </div>

      {/* Info Section */}
      <div className={styles.infoBox}>
        <span className={styles.infoLabel}>تفاصيل البث والمحتوى</span>
        <p className={styles.infoDescription}>
          {liveStream.description || "شاهد البث المباشر لقناة ليبيا بلس الرقمية بجودة عالية. تغطية إخبارية ممتازة وتواصل دائم ومباشر على مدار الساعة لآخر الفعاليات الثقافية والفنية والسياسية في ليبيا."}
        </p>
      </div>
    </div>
  );
}
